    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
    },
  },
  hsts: { maxAge: 31536000, includeSubDomains: true, preload: true },
}));
```

---

### 🟠 4. No Rate Limiting (DoS / Brute-Force Risk)

**Problem:** The server accepts unlimited requests. An attacker can enumerate data or exhaust resources with no friction.

**Fix:**

```js
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // max requests per IP per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});

app.use(limiter); // Apply globally

// Or tighter limits on sensitive endpoints:
const authLimiter = rateLimit({ windowMs: 60_000, max: 10 });
app.use('/login', authLimiter);
```

---

### 🟠 5. No CORS Policy

**Problem:** With no CORS configuration, browser behavior depends on Express defaults — which can be permissive or inconsistent. A malicious site can make cross-origin requests to your API from a victim's browser.

**Fix:**

```js
const cors = require('cors');

app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') ?? ['https://yourdomain.com'],
