  res.json([{ id: 1, name: 'Alice', email: 'alice@example.com' }, ...]);
});
```

**Fix:** Add an authentication middleware. A minimal JWT example:

```js
const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // "Bearer <token>"
  if (!token) return res.status(401).json({ error: 'Unauthorized' });

  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) return res.status(403).json({ error: 'Forbidden' });
    req.user = user;
    next();
  });
}

// Apply to protected routes
app.get('/users', requireAuth, (req, res) => { ... });
```

---

### 🔴 Finding 2 — Sensitive Data Exposure

**OWASP: A02:2021 – Cryptographic Failures / A05:2021 – Security Misconfiguration**

Email addresses are returned to any caller. Even when auth is added, returning PII without a need-to-know principle is risky. API responses should follow the **principle of least privilege** — return only what the caller needs.

**Fix:** Define a response DTO that omits or masks sensitive fields:

```js
function sanitizeUser(user) {
  const { password, ssn, ...safeFields } = user; // strip sensitive fields
  return safeFields;
}

app.get('/users', requireAuth, (req, res) => {
  res.json(users.map(sanitizeUser));
});
```

